public class Solution {
    public ListNode mergeKLists(ListNode[] lists) {
        // Min-heap ordered by node value
        PriorityQueue<ListNode> heap =
            new PriorityQueue<>(Comparator.comparingInt(n -> n.val));

        // Seed: add the head of each non-empty list
        for (ListNode node : lists)
            if (node != null) heap.offer(node);

        ListNode dummy = new ListNode(0);
        ListNode tail = dummy;

        while (!heap.isEmpty()) {
            ListNode node = heap.poll();  // smallest current head
            tail.next = node;
            tail = tail.next;
            if (node.next != null)        // push next from same list
                heap.offer(node.next);
        }
        return dummy.next;
    }
}

public class MedianFinder {
    // Max-heap: lower half (top = max of lower half)
    private PriorityQueue<Integer> lower = new PriorityQueue<>(Collections.reverseOrder());
    // Min-heap: upper half (top = min of upper half)
    private PriorityQueue<Integer> upper = new PriorityQueue<>();

    public void addNum(int num) {
        lower.offer(num);           // always add to lower first
        upper.offer(lower.poll());  // balance: push lower's max to upper
        if (upper.size() > lower.size())  // keep lower >= upper
            lower.offer(upper.poll());
    }

    public double findMedian() {
        if (lower.size() > upper.size())
            return lower.peek();      // odd total: median is lower's max
        return (lower.peek() + upper.peek()) / 2.0;  // even: avg of two middles
    }
}

public class Solution {
    public int leastInterval(char[] tasks, int n) {
        int[] freq = new int[26];
        for (char t : tasks) freq[t - 'A']++;

        // Max-heap: always pick most frequent available task
        PriorityQueue<Integer> maxHeap =
            new PriorityQueue<>(Collections.reverseOrder());
        for (int f : freq) if (f > 0) maxHeap.offer(f);

        int time = 0;
        while (!maxHeap.isEmpty()) {
            List<Integer> temp = new ArrayList<>();
            for (int i = 0; i <= n; i++) {  // one cycle of length n+1
                if (!maxHeap.isEmpty()) temp.add(maxHeap.poll() - 1);
                time++;
                if (maxHeap.isEmpty() && temp.stream().allMatch(x -> x == 0)) break;
            }
            for (int f : temp) if (f > 0) maxHeap.offer(f);  // re-add remaining
        }
        return time;
    }
}

public class Solution {
    public int[] dijkstra(int[][] graph, int src) {
        int n = graph.length;
        int[] dist = new int[n];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;

        // Min-heap: [distance, node]
        PriorityQueue<int[]> heap = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        heap.offer(new int[]{0, src});

        while (!heap.isEmpty()) {
            int[] curr = heap.poll();
            int d = curr[0], u = curr[1];
            if (d > dist[u]) continue;  // stale entry: skip

            for (int[] edge : graph[u]) {  // [neighbor, weight]
                int v = edge[0], w = edge[1];
                if (dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                    heap.offer(new int[]{dist[v], v});
                }
            }
        }
        return dist;
    }
}

